                onClick={onClose}
                className="p-2 bg-slate-700 rounded-full text-slate-400 hover:text-white hover:bg-slate-600 transition-colors"
            >
                <XIcon className="w-5 h-5" />
            </button>
        </div>

        {/* Content */}
